// // If A1 is high and A2 is low, X should output the value of A3; if A1 is low and A2 is high, X should output the value of B1; if both A1 and A2 are high, X should output the value of C1; otherwise, X should default to high.
module top_module(
    output reg X,  // Changed to output reg
    input A1,
    input A2,
    input A3,
    input B1,
    input C1
);// Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB;
    supply0 VNB;

    always @(*) begin
        if (A1 && !A2) begin
            X <= B1;
        end else if (!A1 && A2) begin
            X <= C1;
        end else if (A1 && A2) begin
            X <= A3;
        end else begin
            X <= 0;
        end
    end

endmodule
